// Analyze feed health metrics
const items = $json.records.map(r => r.fields);
const now = new Date();
const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

const feedMetrics = {};
const sources = new Set();

items.forEach(item => {
  const source = item.source || 'Unknown';
  sources.add(source);

  if (!feedMetrics[source]) {
    feedMetrics[source] = {
      source,
      tier: item.source_tier || 'Unknown',
      item_count: 0,
      avg_score: 0,
      last_updated: null,
      status: 'OK'
    };
  }

  feedMetrics[source].item_count += 1;
  feedMetrics[source].avg_score += (item.combined_score || 0);

  const itemDate = new Date(item.published_date);
  if (!feedMetrics[source].last_updated || itemDate > new Date(feedMetrics[source].last_updated)) {
    feedMetrics[source].last_updated = item.published_date;
  }
});

// Calculate averages and health status
Object.values(feedMetrics).forEach(feed => {
  feed.avg_score = Math.round(feed.avg_score / (feed.item_count || 1));

  const lastUpdate = new Date(feed.last_updated);
  const hoursSinceUpdate = (now - lastUpdate) / (1000 * 60 * 60);

  if (hoursSinceUpdate > 48) {
    feed.status = 'STALE';
  } else if (hoursSinceUpdate > 24) {
    feed.status = 'SLOW';
  } else {
    feed.status = 'OK';
  }
});

return {
  total_sources: sources.size,
  total_items_7d: items.length,
  feed_metrics: Object.values(feedMetrics)
};

// Generate health report markdown
const data = $json;
let report = `# Feed Health Report\n\n**Generated**: ${new Date().toLocaleString()}\n\n`;
report += `## Summary\n`;
report += `- Total Sources: ${data.total_sources}\n`;
report += `- Items (7 days): ${data.total_items_7d}\n`;
report += `- Avg Score: ${Math.round(data.feed_metrics.reduce((a,b) => a + b.avg_score, 0) / data.feed_metrics.length)}\n\n`;

report += `## Source Status\n\n`;
data.feed_metrics.forEach(feed => {
  const statusIcon = feed.status === 'OK' ? '✅' : feed.status === 'SLOW' ? '⚠️' : '🔴';
  report += `${statusIcon} **${feed.source}** (Tier ${feed.tier})\n`;
  report += `  - Items (7d): ${feed.item_count}\n`;
  report += `  - Avg Score: ${feed.avg_score}/100\n`;
  report += `  - Last Update: ${new Date(feed.last_updated).toLocaleString()}\n`;
  report += `  - Status: ${feed.status}\n\n`;
});

return { report };

